      bannerBgLo:      '#5a1810',
      bannerFrame:     '#3a3530',  // iron L-brackets on banner
      stencilWarm:     '#f0d088',  // warm cream stencil on banners
      stencilCool:     '#1a0e08',  // dark stencil on light surfaces
      pegboard:        '#6a4828',  // workshop pegboard brown
      pegboardHole:    '#2a1810',
