      shelfDark:       '#1a0e08',  // shelf interior dark
      shelfWood:       '#4a2818',  // shelf wood boards
      shelfWoodHi:     '#7a4828',
      flagRed:         '#a01a14',  // soviet flag
      flagRedHi:       '#c83830',
      flagGold:        '#e8b830',
      flagPole:        '#3a3530',
      lampShade:       '#1a1612',
      lampShadeHi:     '#3a3530',
